"use strict";(self.webpackChunkajudafacitysistemas=self.webpackChunkajudafacitysistemas||[]).push([[1236],{8858:(a,n,t)=>{t.r(n),t.d(n,{assets:()=>p,contentTitle:()=>s,default:()=>g,frontMatter:()=>c,metadata:()=>i,toc:()=>r});var o=t(4848),e=t(8453);const c={title:"Como Criar e Configurar a Chave do Google Maps no Facity Controle?",description:"Precisa ativar os mapas no seu sistema? Siga este guia r\xe1pido para gerar sua chave de API e configur\xe1-la em poucos minutos. PARTE 1: GERAR A CHAVE 1. Acesse:..."},s=void 0,i={id:"configuracoes/como-criar-e-configurar-a-chave-do-google-maps-no-facity-controle-",title:"Como Criar e Configurar a Chave do Google Maps no Facity Controle?",description:"Precisa ativar os mapas no seu sistema? Siga este guia r\xe1pido para gerar sua chave de API e configur\xe1-la em poucos minutos. PARTE 1: GERAR A CHAVE 1. Acesse:...",source:"@site/docs/configuracoes/como-criar-e-configurar-a-chave-do-google-maps-no-facity-controle-.mdx",sourceDirName:"configuracoes",slug:"/configuracoes/como-criar-e-configurar-a-chave-do-google-maps-no-facity-controle-",permalink:"/docs/configuracoes/como-criar-e-configurar-a-chave-do-google-maps-no-facity-controle-",draft:!1,unlisted:!1,tags:[],version:"current",frontMatter:{title:"Como Criar e Configurar a Chave do Google Maps no Facity Controle?",description:"Precisa ativar os mapas no seu sistema? Siga este guia r\xe1pido para gerar sua chave de API e configur\xe1-la em poucos minutos. PARTE 1: GERAR A CHAVE 1. Acesse:..."},sidebar:"tutorialSidebar",previous:{title:"Como criar chave do Google Maps e configurar taxa de entrega (Km)?",permalink:"/docs/configuracoes/como-criar-chave-do-google-maps-e-configurar-taxa-de-entrega--km--"},next:{title:"Como liberar o acesso \xe0 rede local no Google Chrome para usar a balan\xe7a integrada",permalink:"/docs/configuracoes/como-liberar-o-acesso-a-rede-local-no-google-chrome-para-usar-a-balanca-integrada"}},p={},r=[];function l(a){return(0,o.jsx)(o.Fragment,{children:(0,o.jsx)(o.Fragment,{children:(0,o.jsx)("div",{dangerouslySetInnerHTML:{__html:'\n  \n<p></p>\n\n\n\n<p class="has-medium-font-size">Precisa ativar os mapas no seu sistema? Siga este guia r\xe1pido para gerar sua chave de API e configur\xe1-la em poucos minutos.</p>\n\n\n\n<h3 class="wp-block-heading"></h3>\n\n\n\n<h3 class="wp-block-heading has-small-font-size"><strong>Parte 1: </strong>Gerar a Chave</h3>\n\n\n\n<ol start="1" class="wp-block-list">\n<li><strong>Acesse:</strong> <a href="https://mapsplatform.google.com" target="_blank" rel="noreferrer noopener">Google Maps Platform</a><br>e clique em <strong>Criar Conta</strong>.</li>\n</ol>\n\n\n\n<figure class="wp-block-image size-large"><img style="max-width: 100%; height: auto;" loading="lazy" decoding="async" width="1024" height="482" src="https://blog.facity.com.br/wp-content/uploads/2025/12/create-a-conta-1024x482.png" alt="" class="wp-image-1931" srcset="https://manual.facity.com.br/wp-content/uploads/2025/12/create-a-conta-1024x482.png 1024w, https://manual.facity.com.br/wp-content/uploads/2025/12/create-a-conta-300x141.png 300w, https://manual.facity.com.br/wp-content/uploads/2025/12/create-a-conta-768x362.png 768w, https://manual.facity.com.br/wp-content/uploads/2025/12/create-a-conta-720x339.png 720w, https://manual.facity.com.br/wp-content/uploads/2025/12/create-a-conta.png 1315w" sizes="(min-width: 960px) 75vw, 100vw" /></figure>\n\n\n\n<p>    2. <strong>Acesso r\xe1pido:</strong> Se o Google j\xe1 reconhecer seu e-mail, clique em <strong>Pular por enquanto</strong> e depois em <strong>Continuar</strong>. (Caso n\xe3o reconhe\xe7a fa\xe7a login na sua conta)</p>\n\n\n\n<figure class="wp-block-image size-large"><img style="max-width: 100%; height: auto;" loading="lazy" decoding="async" width="1024" height="482" src="https://blog.facity.com.br/wp-content/uploads/2025/12/pule-por-enquanto-1024x482.png" alt="" class="wp-image-1932" srcset="https://manual.facity.com.br/wp-content/uploads/2025/12/pule-por-enquanto-1024x482.png 1024w, https://manual.facity.com.br/wp-content/uploads/2025/12/pule-por-enquanto-300x141.png 300w, https://manual.facity.com.br/wp-content/uploads/2025/12/pule-por-enquanto-768x362.png 768w, https://manual.facity.com.br/wp-content/uploads/2025/12/pule-por-enquanto-720x339.png 720w, https://manual.facity.com.br/wp-content/uploads/2025/12/pule-por-enquanto.png 1315w" sizes="(min-width: 960px) 75vw, 100vw" /></figure>\n\n\n\n<p> 3. Clique em <strong>Continuar</strong>;</p>\n\n\n\n<figure class="wp-block-image size-large"><img style="max-width: 100%; height: auto;" loading="lazy" decoding="async" width="1024" height="482" src="https://blog.facity.com.br/wp-content/uploads/2025/12/continuacao-1024x482.png" alt="" class="wp-image-1933" srcset="https://manual.facity.com.br/wp-content/uploads/2025/12/continuacao-1024x482.png 1024w, https://manual.facity.com.br/wp-content/uploads/2025/12/continuacao-300x141.png 300w, https://manual.facity.com.br/wp-content/uploads/2025/12/continuacao-768x362.png 768w, https://manual.facity.com.br/wp-content/uploads/2025/12/continuacao-720x339.png 720w, https://manual.facity.com.br/wp-content/uploads/2025/12/continuacao.png 1315w" sizes="(min-width: 960px) 75vw, 100vw" /></figure>\n\n\n\n<p>4. <strong>Termos:</strong> Marque a caixa de termos de uso e clique em <strong>Concordar e Continuar</strong>.</p>\n\n\n\n<figure class="wp-block-image size-large"><img style="max-width: 100%; height: auto;" loading="lazy" decoding="async" width="1024" height="482" src="https://blog.facity.com.br/wp-content/uploads/2025/12/concorde-e-continue-1024x482.png" alt="" class="wp-image-1934" srcset="https://manual.facity.com.br/wp-content/uploads/2025/12/concorde-e-continue-1024x482.png 1024w, https://manual.facity.com.br/wp-content/uploads/2025/12/concorde-e-continue-300x141.png 300w, https://manual.facity.com.br/wp-content/uploads/2025/12/concorde-e-continue-768x362.png 768w, https://manual.facity.com.br/wp-content/uploads/2025/12/concorde-e-continue-720x339.png 720w, https://manual.facity.com.br/wp-content/uploads/2025/12/concorde-e-continue.png 1315w" sizes="(min-width: 960px) 75vw, 100vw" /></figure>\n\n\n\n<p>5. <strong>Cart\xe3o de Cr\xe9dito:</strong> O Google pede um m\xe9todo de pagamento para validar a conta (mas oferece um cr\xe9dito gratuito todo m\xeas). Clique no <strong>&#8220;+&#8221;</strong>, insira os dados do cart\xe3o e clique em <strong>Iniciar</strong>.</p>\n\n\n\n<figure class="wp-block-image size-large"><img style="max-width: 100%; height: auto;" loading="lazy" decoding="async" width="1024" height="482" src="https://blog.facity.com.br/wp-content/uploads/2025/12/adicione-metodo-de-pagamento-1024x482.png" alt="" class="wp-image-1935" srcset="https://manual.facity.com.br/wp-content/uploads/2025/12/adicione-metodo-de-pagamento-1024x482.png 1024w, https://manual.facity.com.br/wp-content/uploads/2025/12/adicione-metodo-de-pagamento-300x141.png 300w, https://manual.facity.com.br/wp-content/uploads/2025/12/adicione-metodo-de-pagamento-768x362.png 768w, https://manual.facity.com.br/wp-content/uploads/2025/12/adicione-metodo-de-pagamento-720x339.png 720w, https://manual.facity.com.br/wp-content/uploads/2025/12/adicione-metodo-de-pagamento.png 1315w" sizes="(min-width: 960px) 75vw, 100vw" /></figure>\n\n\n\n<figure class="wp-block-image size-large"><img style="max-width: 100%; height: auto;" loading="lazy" decoding="async" width="1024" height="482" src="https://blog.facity.com.br/wp-content/uploads/2025/12/informacoes-do-cartao-1024x482.png" alt="" class="wp-image-1936" srcset="https://manual.facity.com.br/wp-content/uploads/2025/12/informacoes-do-cartao-1024x482.png 1024w, https://manual.facity.com.br/wp-content/uploads/2025/12/informacoes-do-cartao-300x141.png 300w, https://manual.facity.com.br/wp-content/uploads/2025/12/informacoes-do-cartao-768x362.png 768w, https://manual.facity.com.br/wp-content/uploads/2025/12/informacoes-do-cartao-720x339.png 720w, https://manual.facity.com.br/wp-content/uploads/2025/12/informacoes-do-cartao.png 1315w" sizes="(min-width: 960px) 75vw, 100vw" /></figure>\n\n\n\n<p>6. <strong>Copie o c\xf3digo:</strong> Quando a chave (um c\xf3digo de letras e n\xfameros) aparecer, <strong>copie e guarde ela</strong>. </p>\n\n\n\n<figure class="wp-block-image size-large"><img style="max-width: 100%; height: auto;" loading="lazy" decoding="async" width="1024" height="482" src="https://blog.facity.com.br/wp-content/uploads/2025/12/chave-maps-1024x482.png" alt="" class="wp-image-1937" srcset="https://manual.facity.com.br/wp-content/uploads/2025/12/chave-maps-1024x482.png 1024w, https://manual.facity.com.br/wp-content/uploads/2025/12/chave-maps-300x141.png 300w, https://manual.facity.com.br/wp-content/uploads/2025/12/chave-maps-768x362.png 768w, https://manual.facity.com.br/wp-content/uploads/2025/12/chave-maps-720x339.png 720w, https://manual.facity.com.br/wp-content/uploads/2025/12/chave-maps.png 1315w" sizes="(min-width: 960px) 75vw, 100vw" /></figure>\n\n\n\n<p>Se n\xe3o aparecer de imediato, clique no menu <strong>Chaves e Credenciais</strong> para visualiz\xe1-la.</p>\n\n\n\n<figure class="wp-block-image size-large"><img style="max-width: 100%; height: auto;" loading="lazy" decoding="async" width="1024" height="482" src="https://blog.facity.com.br/wp-content/uploads/2025/12/achar-a-chave-api-1024x482.png" alt="" class="wp-image-1939" srcset="https://manual.facity.com.br/wp-content/uploads/2025/12/achar-a-chave-api-1024x482.png 1024w, https://manual.facity.com.br/wp-content/uploads/2025/12/achar-a-chave-api-300x141.png 300w, https://manual.facity.com.br/wp-content/uploads/2025/12/achar-a-chave-api-768x362.png 768w, https://manual.facity.com.br/wp-content/uploads/2025/12/achar-a-chave-api-720x339.png 720w, https://manual.facity.com.br/wp-content/uploads/2025/12/achar-a-chave-api.png 1315w" sizes="(min-width: 960px) 75vw, 100vw" /></figure>\n\n\n\n<h3 class="wp-block-heading">2. Colocando a chave no sistema Facity Controle</h3>\n\n\n\n<p class="has-medium-font-size">Agora, voc\xea precisa &#8220;avisar&#8221; ao seu sistema qual \xe9 a sua chave.</p>\n\n\n\n<ol class="wp-block-list">\n<li><strong>Login:</strong> Acesse o seu painel do <strong>Facity Controle</strong>.</li>\n</ol>\n\n\n\n<figure class="wp-block-image size-large"><img style="max-width: 100%; height: auto;" loading="lazy" decoding="async" width="1024" height="482" src="https://blog.facity.com.br/wp-content/uploads/2025/12/entrando-no-sistema-pra-colar-api-1024x482.png" alt="" class="wp-image-1941" srcset="https://manual.facity.com.br/wp-content/uploads/2025/12/entrando-no-sistema-pra-colar-api-1024x482.png 1024w, https://manual.facity.com.br/wp-content/uploads/2025/12/entrando-no-sistema-pra-colar-api-300x141.png 300w, https://manual.facity.com.br/wp-content/uploads/2025/12/entrando-no-sistema-pra-colar-api-768x362.png 768w, https://manual.facity.com.br/wp-content/uploads/2025/12/entrando-no-sistema-pra-colar-api-720x339.png 720w, https://manual.facity.com.br/wp-content/uploads/2025/12/entrando-no-sistema-pra-colar-api.png 1315w" sizes="(min-width: 960px) 75vw, 100vw" /></figure>\n\n\n\n<p>   2. <strong>Configura\xe7\xf5es:</strong> No menu lateral, clique em <strong>Configura\xe7\xf5es</strong></p>\n\n\n\n<figure class="wp-block-image size-large"><img style="max-width: 100%; height: auto;" loading="lazy" decoding="async" width="1024" height="482" src="https://blog.facity.com.br/wp-content/uploads/2025/12/configuracoes-1024x482.png" alt="" class="wp-image-1942" srcset="https://manual.facity.com.br/wp-content/uploads/2025/12/configuracoes-1024x482.png 1024w, https://manual.facity.com.br/wp-content/uploads/2025/12/configuracoes-300x141.png 300w, https://manual.facity.com.br/wp-content/uploads/2025/12/configuracoes-768x362.png 768w, https://manual.facity.com.br/wp-content/uploads/2025/12/configuracoes-720x339.png 720w, https://manual.facity.com.br/wp-content/uploads/2025/12/configuracoes.png 1315w" sizes="(min-width: 960px) 75vw, 100vw" /></figure>\n\n\n\n<p>  3. No final da p\xe1gina que abrir, clique novamente no bot\xe3o <strong>Configura\xe7\xf5es</strong>.</p>\n\n\n\n<figure class="wp-block-image size-large"><img style="max-width: 100%; height: auto;" loading="lazy" decoding="async" width="1024" height="482" src="https://blog.facity.com.br/wp-content/uploads/2025/12/config-1-1024x482.png" alt="" class="wp-image-1943" srcset="https://manual.facity.com.br/wp-content/uploads/2025/12/config-1-1024x482.png 1024w, https://manual.facity.com.br/wp-content/uploads/2025/12/config-1-300x141.png 300w, https://manual.facity.com.br/wp-content/uploads/2025/12/config-1-768x362.png 768w, https://manual.facity.com.br/wp-content/uploads/2025/12/config-1-720x339.png 720w, https://manual.facity.com.br/wp-content/uploads/2025/12/config-1.png 1315w" sizes="(min-width: 960px) 75vw, 100vw" /></figure>\n\n\n\n<p>  4. <strong>Busca:</strong> No campo de pesquisa, digite a palavra <strong>Maps</strong>.</p>\n\n\n\n<figure class="wp-block-image size-large"><img style="max-width: 100%; height: auto;" loading="lazy" decoding="async" width="1024" height="482" src="https://blog.facity.com.br/wp-content/uploads/2025/12/busque-nome-maps-1024x482.png" alt="" class="wp-image-1944" srcset="https://manual.facity.com.br/wp-content/uploads/2025/12/busque-nome-maps-1024x482.png 1024w, https://manual.facity.com.br/wp-content/uploads/2025/12/busque-nome-maps-300x141.png 300w, https://manual.facity.com.br/wp-content/uploads/2025/12/busque-nome-maps-768x362.png 768w, https://manual.facity.com.br/wp-content/uploads/2025/12/busque-nome-maps-720x339.png 720w, https://manual.facity.com.br/wp-content/uploads/2025/12/busque-nome-maps.png 1315w" sizes="(min-width: 960px) 75vw, 100vw" /></figure>\n\n\n\n<p>  5. <strong>Editar:</strong> Voc\xea ver\xe1 duas op\xe7\xf5es de API</p>\n\n\n\n<figure class="wp-block-image size-large"><img style="max-width: 100%; height: auto;" loading="lazy" decoding="async" width="1024" height="482" src="https://blog.facity.com.br/wp-content/uploads/2025/12/altere-essas-chaves-1024x482.png" alt="" class="wp-image-1945" srcset="https://manual.facity.com.br/wp-content/uploads/2025/12/altere-essas-chaves-1024x482.png 1024w, https://manual.facity.com.br/wp-content/uploads/2025/12/altere-essas-chaves-300x141.png 300w, https://manual.facity.com.br/wp-content/uploads/2025/12/altere-essas-chaves-768x362.png 768w, https://manual.facity.com.br/wp-content/uploads/2025/12/altere-essas-chaves-720x339.png 720w, https://manual.facity.com.br/wp-content/uploads/2025/12/altere-essas-chaves.png 1315w" sizes="(min-width: 960px) 75vw, 100vw" /></figure>\n\n\n\n<p>  6. Clique no <strong>\xedcone verde (l\xe1pis/editar)</strong> em cada uma delas.</p>\n\n\n\n<figure class="wp-block-image size-large"><img style="max-width: 100%; height: auto;" loading="lazy" decoding="async" width="1024" height="482" src="https://blog.facity.com.br/wp-content/uploads/2025/12/editar-chave-1024x482.png" alt="" class="wp-image-1946" srcset="https://manual.facity.com.br/wp-content/uploads/2025/12/editar-chave-1024x482.png 1024w, https://manual.facity.com.br/wp-content/uploads/2025/12/editar-chave-300x141.png 300w, https://manual.facity.com.br/wp-content/uploads/2025/12/editar-chave-768x362.png 768w, https://manual.facity.com.br/wp-content/uploads/2025/12/editar-chave-720x339.png 720w, https://manual.facity.com.br/wp-content/uploads/2025/12/editar-chave.png 1315w" sizes="(min-width: 960px) 75vw, 100vw" /></figure>\n\n\n\n<p>  7. <strong>Colar e Salvar:</strong> Apague o que estiver no campo, <strong>cole a sua nova chave</strong> e clique em <strong>Salvar</strong>.</p>\n\n\n\n<figure class="wp-block-image size-large"><img style="max-width: 100%; height: auto;" loading="lazy" decoding="async" width="1024" height="482" src="https://blog.facity.com.br/wp-content/uploads/2025/12/cole-a-chave-em-ambos-campos-e-clique-em-ok-1024x482.png" alt="" class="wp-image-1947" srcset="https://manual.facity.com.br/wp-content/uploads/2025/12/cole-a-chave-em-ambos-campos-e-clique-em-ok-1024x482.png 1024w, https://manual.facity.com.br/wp-content/uploads/2025/12/cole-a-chave-em-ambos-campos-e-clique-em-ok-300x141.png 300w, https://manual.facity.com.br/wp-content/uploads/2025/12/cole-a-chave-em-ambos-campos-e-clique-em-ok-768x362.png 768w, https://manual.facity.com.br/wp-content/uploads/2025/12/cole-a-chave-em-ambos-campos-e-clique-em-ok-720x339.png 720w, https://manual.facity.com.br/wp-content/uploads/2025/12/cole-a-chave-em-ambos-campos-e-clique-em-ok.png 1315w" sizes="(min-width: 960px) 75vw, 100vw" /></figure>\n\n\n\n<figure class="wp-block-image size-large"><img style="max-width: 100%; height: auto;" loading="lazy" decoding="async" width="1024" height="482" src="https://blog.facity.com.br/wp-content/uploads/2025/12/cole-ambos-cambos-e-clique-ok-2-1024x482.png" alt="" class="wp-image-1949" srcset="https://manual.facity.com.br/wp-content/uploads/2025/12/cole-ambos-cambos-e-clique-ok-2-1024x482.png 1024w, https://manual.facity.com.br/wp-content/uploads/2025/12/cole-ambos-cambos-e-clique-ok-2-300x141.png 300w, https://manual.facity.com.br/wp-content/uploads/2025/12/cole-ambos-cambos-e-clique-ok-2-768x362.png 768w, https://manual.facity.com.br/wp-content/uploads/2025/12/cole-ambos-cambos-e-clique-ok-2-720x339.png 720w, https://manual.facity.com.br/wp-content/uploads/2025/12/cole-ambos-cambos-e-clique-ok-2.png 1315w" sizes="(min-width: 960px) 75vw, 100vw" /></figure>\n\n\n\n<p class="has-medium-font-size"><strong>Pronto! O seu Google Maps j\xe1 deve estar funcionando.</strong></p>\n\n'}})})})}function g(a={}){const{wrapper:n}={...(0,e.R)(),...a.components};return n?(0,o.jsx)(n,{...a,children:(0,o.jsx)(l,{...a})}):l()}},8453:(a,n,t)=>{t.d(n,{R:()=>s,x:()=>i});var o=t(6540);const e={},c=o.createContext(e);function s(a){const n=o.useContext(c);return o.useMemo((function(){return"function"==typeof a?a(n):{...n,...a}}),[n,a])}function i(a){let n;return n=a.disableParentContext?"function"==typeof a.components?a.components(e):a.components||e:s(a.components),o.createElement(c.Provider,{value:n},a.children)}}}]);